var e=[{id:`L2_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`이번엔 그쪽으로 간다!`,JPN:`今度はそっちに行く！`,ENG:`This one’s headed over there!`,TWN:`這次往那裡走！`},stage:{bg:`FOREST_NORMAL`,slots:{L:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`확인했어! 내가 발사좌표로 유인하지!`,JPN:`確認した！　私が発射の座標へと誘導しよう！`,ENG:`I see it! I'll lure it to the coordinates!`,TWN:`確認完畢！我會將它們引到發射座標！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:null,R:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_SERIOUS`}}}},{id:`L9_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_NULL`,text:{KOREA:`놈이 사정권 안으로 들어갔습니다!`,JPN:`やつが射程圏内に入りました！`,ENG:`The monster's within range, sir!`,TWN:`進入射程範圍內！`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`지금이다! 발사!`,JPN:`今だ！　発射！`,ENG:`Now! FIRE!!`,TWN:`就是現在！發射！`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_SERIOUS`}}}},{id:`L17_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`방금 그게 마지막 놈이었나?`,JPN:`今のが最後か？`,ENG:`Was that the last of them?`,TWN:`剛才那隻是最後一個嗎？`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:null,C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_SURPRISE`}}}},{id:`L18_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_NULL`,text:{KOREA:`아무래도 그런 것 같습니다. 침식파가 더는 감지되지 않아요.`,JPN:`どうやらそのようです。もう侵食波が感知されません。`,ENG:`I believe so. We’re not sensing any more Corruption ray.`,TWN:`好像是，目前沒有再感應到侵蝕波。`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_SURPRISE`}}}},{id:`L19_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`보고도 믿기지 않는군. 저 덩치 큰 놈들을 전부 해치우다니…….`,JPN:`この目で見ても信じられないな。あのデカいやつらを全部やっつけるなんて……`,ENG:`I can't believe it. We got all of those giant monsters...`,TWN:`真不敢置信，竟然把塊頭那麼大的傢伙全都解決掉了……`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`헉… 헉… 끝난 건가?`,JPN:`はあ……はあ……終わったのか？`,ENG:`*Huff... Huff...* Is it over?`,TWN:`呼…呼…結束了嗎？`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_DESPAIR`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`침식파는 사라졌어. 우리가 모두 처리한 것 같아.`,JPN:`侵食波は消えた。すべて片付けたみたい。`,ENG:`Corruption ray's gone. I think we got all of them.`,TWN:`侵蝕波消失了，好像都解決掉了。`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`그거… 다행이군.`,JPN:`それは……良かったな。`,ENG:`That's... a relief.`,TWN:`那…就好。`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`혼란스러운 와중에 대원들이 다들 제 역할을 잘 해줬어.`,JPN:`混乱してる中でも隊員それぞれが自分の役割をよく果たしてくれた。`,ENG:`Everyone did an excellent job despite the chaos.`,TWN:`混亂之中隊員們也都有各盡其職，`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`평소에도… 훈련이 잘 되어 있었던 거겠지.`,JPN:`普段の……訓練のたまものだろう。`,ENG:`I guess... that means they were trained well.`,TWN:`應該是…平時就訓練有素吧？`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`겸손 떨 필요 없어.`,JPN:`謙遜する必要はない。`,ENG:`There no need to be modest.`,TWN:`不需要這麼謙虛。`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`당신의 지휘가 아니었으면…`,JPN:`あなたの指揮がなかったら……`,ENG:`If it wasn't for your command─`,TWN:`若不是有你的指揮…`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};